package com.example.factly.data.repositories

import com.example.factly.data.models.Fact

object FactRepository {

    val allTopics = listOf(
        "Science", "Sports", "Geography", "Technology",
        "Food", "Animals", "Space", "Human Body", "History"
    )

    private val facts = listOf(
        // Science
        Fact(1, "Honey never spoils. Archaeologists found pots of honey in ancient Egyptian tombs that are over 3,000 years old and still edible.", "Science",
            "Honey's extraordinary shelf life comes from three properties: its low water content (around 17-20%), which prevents microbial growth; its high sugar concentration, which draws moisture out of any bacteria; and its natural acidity (pH 3.2–4.5). Honey also contains hydrogen peroxide produced by the enzyme glucose oxidase, acting as a natural antimicrobial. As long as it's stored sealed and away from moisture, honey can last indefinitely."),
        Fact(2, "A bolt of lightning is five times hotter than the surface of the sun.", "Science",
            "The surface of the sun reaches about 5,500°C (9,932°F), while a lightning bolt superheats the surrounding air to roughly 30,000°C (54,000°F) in a fraction of a second. This extreme, rapid heating causes the air to expand violently, producing the shockwave we hear as thunder. Despite its intensity, a lightning bolt is only about 2-3 cm wide and lasts mere milliseconds."),
        Fact(3, "The Eiffel Tower can grow 6 inches taller in summer due to thermal expansion.", "Science",
            "Metal expands when heated — a property called thermal expansion. The Eiffel Tower, made of iron, can grow by up to 15 cm (about 6 inches) on hot summer days compared to cold winter days. This is because heat increases the vibration of iron atoms, causing the lattice structure to spread apart. Engineers account for thermal expansion in large metal structures using expansion joints."),
        Fact(4, "Octopuses have three hearts and blue blood.", "Science",
            "Octopuses have one systemic heart that pumps blood through the body and two branchial hearts that pump blood through the gills. Their blood is blue because it uses hemocyanin — a copper-based protein — instead of the iron-based hemoglobin found in human blood. Hemocyanin is less efficient at carrying oxygen than hemoglobin, but it works better in cold, low-oxygen environments like the deep sea."),
        Fact(5, "Water can boil and freeze at the same time. This is called the triple point.", "Science",
            "The triple point is the exact temperature and pressure at which all three phases of a substance — solid, liquid, and gas — coexist in thermodynamic equilibrium. For water, this occurs at exactly 273.16 K (0.01°C) and 611.657 pascals. At this precise point, ice, liquid water, and water vapor are all stable simultaneously. Scientists use the triple point of water as a fundamental calibration reference for temperature scales."),
        Fact(6, "Sound travels about four times faster through water than through air.", "Science",
            "Sound travels at roughly 343 m/s in air at room temperature, but about 1,480 m/s in water. This is because sound propagates through the compression and expansion of a medium's molecules. Water molecules are much closer together and more tightly bonded than air molecules, allowing the pressure wave to transfer more quickly. This property is exploited in sonar systems used by submarines and marine biologists."),
        Fact(7, "A teaspoonful of neutron star material would weigh about 10 million tonnes.", "Science",
            "Neutron stars are the collapsed remnants of massive stars after supernova explosions. Gravity compresses their cores so intensely that protons and electrons are forced together to form neutrons, packed at nuclear density — roughly 4 × 10¹⁷ kg/m³. A teaspoon (about 5 ml) of this material would weigh approximately 5.5 billion tons. Their gravity is so extreme that escape velocity at the surface is roughly half the speed of light."),
        Fact(8, "Glass is actually a super-cooled liquid, not a solid. It flows extremely slowly over centuries.", "Science",
            "Glass is an amorphous solid — its atoms are arranged randomly like a liquid, not in the crystalline lattice of a true solid. This has led to the popular claim that glass 'flows' downward over time, supposedly evidenced by old windows being thicker at the bottom. However, modern scientists have largely debunked the slow-flow idea; old glass was simply made unevenly, and installers placed the thicker edge downward. Glass technically fits a category between solid and liquid."),
        Fact(9, "The human eye can distinguish approximately 10 million different colors.", "Science",
            "Color vision in humans is made possible by three types of cone cells in the retina, each sensitive to different wavelengths: red (long), green (medium), and blue (short). The brain combines signals from these cones to perceive the full color spectrum. With roughly 100 levels of sensitivity per cone type, the theoretical number of distinguishable colors reaches around 10 million. Some people (tetrachromats) have a fourth cone type and can see even more shades."),
        Fact(10, "Rubber bands last longer when refrigerated because cold slows the degradation of their polymers.", "Science",
            "Natural rubber is made of long polymer chains of polyisoprene. Over time, oxygen and ozone in the air attack the double bonds in these chains, causing them to break — a process called oxidative degradation. Lower temperatures slow the kinetic energy of molecules, reducing the rate of these chemical reactions. Refrigerating rubber bands preserves their elasticity significantly longer than storing them at room temperature."),
        Fact(11, "A day on Mars is 24 hours and 37 minutes, remarkably close to an Earth day.", "Science",
            "A Martian solar day, called a 'sol,' lasts 24 hours, 39 minutes, and 35 seconds — only about 2.7% longer than an Earth day. This similarity was one of the reasons early scientists found Mars an intriguing candidate for life. The Mars rovers (Curiosity, Perseverance) operate on Martian time, requiring their NASA controllers to shift their work schedules by 40 minutes each day, which over weeks diverges significantly from normal Earth schedules."),

        // Sports
        Fact(12, "The first Olympic Games were held in 776 BC in ancient Greece.", "Sports",
            "The ancient Olympic Games were a religious festival held in Olympia, Greece, in honor of Zeus. They were held every four years — a period called an 'Olympiad' — and participants came from all over the Greek world. The original event was a single foot race called the 'stadion.' Over centuries, events like wrestling, discus, and chariot racing were added. The games were banned in 393 AD by Roman Emperor Theodosius I. The modern Olympics were revived in Athens in 1896."),
        Fact(13, "A regulation NBA basketball must be inflated to between 7.5 and 8.5 PSI.", "Sports",
            "NBA regulations specify that a basketball must be inflated to 7.5 to 8.5 pounds per square inch (PSI). Proper inflation affects bounce consistency, grip, and the overall game experience. Balls inflated below this range bounce lower and feel sluggish; over-inflated balls are too bouncy and harder to control. The balls used in NBA games are made of leather and hand-selected for quality; each game typically uses multiple balls."),
        Fact(14, "Golf is the only sport played on the moon. Alan Shepard hit a golf ball there in 1971.", "Sports",
            "During the Apollo 14 mission in February 1971, astronaut Alan Shepard smuggled a makeshift golf club head onto the lunar module and attached it to a rock sample collector handle. He hit two golf balls on the lunar surface — the second one, he said, went 'miles and miles' due to the moon's gravity being one-sixth of Earth's and the absence of air resistance. The ball actually traveled an estimated 180-200 meters, but Shepard's boast has become legendary in sports trivia."),
        Fact(15, "The marathon distance of 26.2 miles was standardized at the 1908 London Olympics.", "Sports",
            "The marathon distance was set at 26 miles and 385 yards (42.195 km) at the 1908 London Olympics to accommodate the British royal family. The race was originally set to start at Windsor Castle (so the royal children could watch from their nursery window) and finish in front of the royal box at the Olympic stadium — measuring exactly 26 miles 385 yards. This distance was formally adopted by the IAAF in 1921 as the standard marathon length worldwide."),
        Fact(16, "Table tennis balls can travel at speeds of up to 150 km/h during professional matches.", "Sports",
            "Professional table tennis players generate extraordinary spin and speed — the ball can travel at over 150 km/h on a smash. The sport requires reaction times of around 0.25 seconds or less. Modern table tennis balls are 40mm in diameter and made of celluloid or plastic. In 2000, the ball size was increased from 38mm to slow the game slightly and make it more television-friendly. The sport is the most-played racket sport in the world by participation."),
        Fact(17, "Usain Bolt reached approximately 44.72 km/h during his record 100m sprint.", "Sports",
            "During his world-record 9.58-second 100m sprint at the 2009 World Championships in Berlin, Usain Bolt reached a top speed of 44.72 km/h (27.79 mph) between the 60m and 80m marks. His stride length at peak speed was about 2.44 meters, with a stride frequency of roughly 4.4 strides per second. Scientists have calculated that Bolt was not at his peak physical potential, suggesting even faster times may be theoretically achievable."),
        Fact(18, "Archery was removed from the Olympics in 1920 and reinstated in 1972.", "Sports",
            "Archery featured in the 1900, 1904, 1908, and 1920 Olympics before being dropped due to a lack of international standardization in rules. During its early Olympic years, each host nation used different formats and distances, making competition inconsistent. The sport was reinstated at the 1972 Munich Olympics after the World Archery Federation (FITA) established unified international rules. Today Olympic archery uses the recurve bow at a distance of 70 meters."),
        Fact(19, "The Tour de France covers roughly 3,500 km and burns around 120,000 calories per rider.", "Sports",
            "The Tour de France is one of the most physically demanding endurance events in the world. Spanning 21 stages over 23 days, riders cover approximately 3,500 km through France and neighboring countries. Each rider burns an estimated 5,000–8,000 calories per stage, totaling around 120,000 calories over the full race — roughly equivalent to 60 days of normal food intake for an average person. Riders eat up to 9,000 calories a day during the event."),
        Fact(20, "The longest tennis match in history lasted 11 hours and 5 minutes at Wimbledon 2010.", "Sports",
            "The match between John Isner (USA) and Nicolas Mahut (France) at Wimbledon 2010 lasted 11 hours and 5 minutes spread over three days. The final set alone went 138-138 games, totaling 183 games overall. Isner ultimately won 70-68 in the fifth set. The match broke virtually every record for a Grand Slam tennis match and led Wimbledon to introduce a final-set tiebreak rule at 12-12 starting in 2019."),
        Fact(21, "Michael Phelps holds more Olympic gold medals than 67 countries have ever won combined.", "Sports",
            "Michael Phelps won 23 Olympic gold medals across the 2000, 2004, 2008, 2012, and 2016 Games, making him the most decorated Olympian of all time with 28 total medals. Remarkably, 67 countries in Olympic history have won fewer than 23 gold medals in total. Phelps dominated swimming events from the 100m butterfly to the 400m individual medley, breaking world records throughout his career."),
        Fact(22, "A standard soccer ball is made of 32 panels: 20 hexagons and 12 pentagons.", "Sports",
            "The classic black-and-white soccer ball (used officially from 1970 onwards) is a truncated icosahedron — a geometric shape with 32 faces: 20 regular hexagons and 12 regular pentagons. The pentagons are traditionally black and the hexagons white. This design was introduced at the 1970 FIFA World Cup in Mexico partly to make the ball more visible on black-and-white televisions. Modern balls increasingly use different panel configurations for better aerodynamics."),

        // Geography
        Fact(23, "The Pacific Ocean is larger than all landmasses on Earth combined.", "Geography",
            "The Pacific Ocean covers approximately 165 million km² — more than the total combined land area of all continents on Earth, which is about 148 million km². It spans from the Arctic in the north to the Antarctic in the south, and from Asia and Australia in the west to the Americas in the east. The Pacific also contains the deepest point on Earth: the Challenger Deep in the Mariana Trench, at approximately 10,935 meters below sea level."),
        Fact(24, "Vatican City is the smallest country in the world.", "Geography",
            "Vatican City covers just 0.44 km² (44 hectares) within Rome, Italy, making it the world's smallest internationally recognized independent state by both area and population (around 800 people). It became an independent state in 1929 through the Lateran Treaty between the Holy See and Italy. Despite its tiny size, Vatican City has its own postal system, bank, radio station, railway station, and is the headquarters of the Roman Catholic Church."),
        Fact(25, "Russia has 11 time zones, more than any other country.", "Geography",
            "Russia spans approximately 9,000 km from east to west — covering about one-eighth of Earth's total landmass — resulting in 11 time zones, the most of any country. The easternmost tip of Russia (near the Bering Strait) is actually so far east it is only about 3.8 km from Alaska. When it is midnight in Kaliningrad (Russia's westernmost exclave), it is already 10 AM the next day in Kamchatka in the far east."),
        Fact(26, "Canada has more lakes than all other countries combined.", "Geography",
            "Canada is home to an estimated 879,800 lakes larger than 10 km², representing approximately 62% of the world's total lake count. This is largely a legacy of the last ice age, when glaciers carved out depressions across the Canadian Shield that subsequently filled with water. The Great Lakes (shared with the USA) contain about 21% of the world's surface fresh water. Canada also has extensive river systems draining into three oceans."),
        Fact(27, "The Sahara Desert is roughly the same size as the contiguous United States.", "Geography",
            "The Sahara Desert spans about 9.2 million km² across North Africa, making it the world's largest hot desert (cold deserts like Antarctica are larger). This area is almost exactly the same as the contiguous 48 US states (about 8 million km²). The Sahara is not entirely sand — only about 25% is sand dunes (ergs); the rest consists of gravel plains (regs), rocky plateaus (hamada), and occasional oases. Temperatures can reach 58°C (136°F)."),
        Fact(28, "Mount Everest grows about 4 mm taller every year due to tectonic uplift.", "Geography",
            "Mount Everest sits at the collision boundary of the Indian and Eurasian tectonic plates. As India continues to push northward into Asia, the Himalayas are still being pushed upward at a rate of about 4-5 mm per year. However, erosion from wind and snow partially counteracts this growth. The current official height of Everest is 8,848.86 m, as measured by a joint Chinese-Nepalese survey in 2020 — slightly higher than the previous measurement of 8,848 m."),
        Fact(29, "The Amazon River discharges more water than the next seven largest rivers combined.", "Geography",
            "The Amazon River discharges approximately 209,000 m³ of water per second into the Atlantic Ocean — about 20% of all fresh water that flows into the world's oceans. This outflow is so massive that it significantly dilutes the salt content of the Atlantic for hundreds of kilometers offshore. The Amazon basin covers 7 million km² across 9 countries and contains the largest tropical rainforest on Earth, home to an estimated 10% of all species on the planet."),
        Fact(30, "Australia is wider than the moon.", "Geography",
            "Australia measures approximately 4,000 km from its west coast to its east coast. The Moon's diameter is about 3,474 km. This comparison highlights Australia's vast size — despite being the smallest continent, it stretches wider than Earth's natural satellite. Australia is also the world's sixth-largest country by total area at 7.69 million km², and the only country to govern an entire continent."),
        Fact(31, "There are more pyramids in Sudan than in Egypt.", "Geography",
            "Sudan is home to approximately 200-255 ancient pyramids, compared to Egypt's roughly 138. These Nubian pyramids were built by the rulers of the ancient Kushite kingdoms, which flourished between 700 BC and 350 AD. Sudanese pyramids are generally smaller and have steeper angles (around 65-70°) compared to Egyptian pyramids. Many are located at sites like Meroe, Nuri, and El-Kurru and are UNESCO World Heritage Sites."),
        Fact(32, "The Dead Sea is so salty that people float effortlessly.", "Geography",
            "The Dead Sea has a salinity of about 34% — roughly 10 times saltier than the average ocean. This extreme salinity makes the water so dense that human bodies float effortlessly on the surface. The high salt and mineral concentration also means virtually no aquatic life can survive in it, hence the name 'Dead Sea.' It sits at 430 meters below sea level, making it the lowest point on Earth's surface. It has been shrinking rapidly due to water diversion from the Jordan River."),
        Fact(33, "Iceland has no mosquitoes because of its climate and geology.", "Geography",
            "Iceland is one of the very few inhabited places on Earth with no mosquito population. The reason is a combination of factors: Iceland's climate goes through rapid freeze-thaw cycles that disrupt the mosquito life cycle; the water chemistry and temperature of pools where mosquitoes breed is unsuitable; and there are no suitable still, warm bodies of water in early spring when larvae typically hatch. Greenland, by contrast, does have mosquitoes despite being colder."),

        // Technology
        Fact(34, "The term 'bug' in programming came from an actual insect found in a computer in 1947.", "Technology",
            "On September 9, 1947, Grace Hopper's team at Harvard found a moth trapped in a relay of the Mark II computer, causing a malfunction. The moth was taped into the logbook with the note 'First actual case of bug being found.' However, the word 'bug' to mean a technical error predates this — Thomas Edison used it in 1878. Grace Hopper did popularize the term in computing, and the logbook page is now displayed at the Smithsonian Institution."),
        Fact(35, "The first website ever created is still online today.", "Technology",
            "The first website, created by Tim Berners-Lee at CERN, went online on August 6, 1991. The site was hosted on a NeXT computer at CERN and described the World Wide Web project itself. The original URL was http://info.cern.ch/hypertext/WWW/TheProject.html. CERN restored the site in 2013 as part of a project to preserve the web's history, and it remains accessible today. Berners-Lee invented the web as a tool for scientists to share information across the internet."),
        Fact(36, "More than 90% of the world's currency exists only digitally.", "Technology",
            "Of the total money supply in the global economy, only about 8-10% exists as physical cash (coins and banknotes). The remaining 90%+ exists purely as digital entries in bank ledgers and electronic payment systems. This digital money is created through fractional reserve banking — when banks issue loans, they effectively create new digital money. The total global money supply (M2 measure) is estimated at over $100 trillion, while physical currency in circulation is far less."),
        Fact(37, "The first computer mouse was made of wood and invented by Doug Engelbart in 1964.", "Technology",
            "Douglas Engelbart invented the computer mouse in 1964 at the Stanford Research Institute. The prototype was a small wooden shell with two metal wheels that tracked movement in X and Y directions. Engelbart called it a 'mouse' because the cord at the back reminded him of a mouse's tail. He publicly demonstrated it in what became known as 'The Mother of All Demos' in 1968, alongside video conferencing, hypertext, and collaborative editing — all decades before they became mainstream."),
        Fact(38, "There are more possible chess games than atoms in the observable universe.", "Technology",
            "The number of possible unique chess games is estimated at around 10¹²⁰ (a googol squared), known as the Shannon number. The observable universe contains an estimated 10⁸⁰ atoms. This staggering complexity means that no computer, however powerful, can brute-force all possible chess positions. Chess engines like Stockfish and AlphaZero instead use evaluation functions and tree-pruning algorithms (like alpha-beta pruning) to identify the best moves without exhaustively calculating every possibility."),
        Fact(39, "Modern smartphones have more computing power than NASA had during the Apollo moon landings.", "Technology",
            "The Apollo Guidance Computer (AGC) used during the 1969 moon landing had a clock speed of 2.048 MHz and 4 KB of RAM. A modern mid-range smartphone runs at over 2 GHz (2,000 MHz) with 4+ GB of RAM — roughly a million times more powerful. The AGC was, however, a marvel of its era: it was one of the first computers to use integrated circuits and was designed to be extremely reliable, operating flawlessly in the vacuum of space under extreme conditions."),
        Fact(40, "About 3.5 billion Google searches are made every day.", "Technology",
            "Google processes approximately 3.5 billion search queries per day — about 40,000 per second and over 1.2 trillion per year. Google holds roughly 92% of the global search engine market share. Each query triggers a complex process: checking the index of over 130 trillion web pages, running ranking algorithms (including PageRank and hundreds of other signals), and returning results in under half a second. Google's search infrastructure runs on distributed data centers worldwide."),
        Fact(41, "Wi-Fi was invented accidentally while scientists were trying to detect mini black holes.", "Technology",
            "Australian astrophysicist John O'Sullivan and his team at CSIRO were working on experiments related to detecting micro black holes using radio waves in the 1970s-80s. The signal processing techniques they developed to clean up radio wave echoes became the foundation for Wi-Fi technology — officially IEEE 802.11. CSIRO patented the key Wi-Fi technology in 1996 and later received over $430 million in royalties from major tech companies after successful patent litigation."),
        Fact(42, "The first domain name ever registered was Symbolics.com on March 15, 1985.", "Technology",
            "Symbolics.com was registered by Symbolics, Inc., a Massachusetts computer company that manufactured Lisp machines, making it the first .com domain name in history. At the time, the internet was a small academic and military network, and domain registration was free and unregulated. The domain changed hands multiple times and is now owned by a startup called XF.com Investments. By comparison, Google.com was registered in 1997, and Amazon.com in 1994."),
        Fact(43, "Email is older than the World Wide Web.", "Technology",
            "Ray Tomlinson sent the first email in 1971 over ARPANET — the precursor to the modern internet. He chose the '@' symbol to separate the user name from the host computer, establishing the email address format still used today. The World Wide Web, by contrast, was invented by Tim Berners-Lee in 1989 and went public in 1991. So email predates the web by approximately 20 years. Tomlinson reportedly could not remember what the first email said, describing it as 'something like QWERTYUIOP.'"),
        Fact(44, "The Apollo 11 guidance computer had less processing power than a modern USB cable.", "Technology",
            "The Apollo Guidance Computer ran at 2.048 MHz with 4 KB of RAM and 72 KB of read-only rope memory. Modern USB-C cables with active electronics — such as the Texas Instruments HD3SS3220 controller — contain embedded chips that are orders of magnitude more powerful than the AGC. Some modern 'smart' USB cables contain microcontrollers with 48 MHz processors and 256 KB of flash memory. The AGC, however, was purpose-built and incredibly robust for its mission."),

        // Food
        Fact(45, "Bananas are berries, but strawberries are not.", "Food",
            "In botanical terms, a berry is a fruit that develops from a single ovary and has seeds embedded in the flesh. Bananas qualify: they develop from a single flower with one ovary. Strawberries, on the other hand, are 'accessory fruits' or 'false berries' — the fleshy part develops from the receptacle (the part holding the flower), not the ovary. Other botanical berries include tomatoes, grapes, kiwis, and avocados. The culinary definition of 'berry' is much looser than the botanical one."),
        Fact(46, "Avocados are fruits and technically a type of berry.", "Food",
            "Botanically, an avocado is a single-seeded berry. It develops from a single flower with one ovary, has a fleshy pericarp (the edible part), and one large seed. Avocados are native to south-central Mexico and were cultivated by Mesoamerican civilizations for thousands of years. The Hass avocado, the most common variety globally, traces back to a single tree grown by Rudolph Hass in California in the 1920s. All commercial Hass avocados are clones grafted from that original tree."),
        Fact(47, "Honey never spoils and has been found edible in 3,000-year-old Egyptian tombs.", "Food",
            "Honey's near-indestructibility is due to its low moisture content, high sugar concentration, and acidic pH. These properties create an environment hostile to bacteria and mold. Additionally, bees add the enzyme glucose oxidase to honey, which slowly releases hydrogen peroxide — a natural antimicrobial agent. Sealed pots of honey found in ancient Egyptian tombs have been tasted by archaeologists and found to still be edible. Crystallized honey is still good — it can be gently warmed to return it to liquid form."),
        Fact(48, "Almonds are part of the peach family.", "Food",
            "Almonds (Prunus amygdalus) are closely related to peaches, cherries, and plums — all members of the genus Prunus in the family Rosaceae. What we eat as an 'almond' is actually the seed of a drupe fruit (like a peach), found inside the hard pit. The outer hull of the almond fruit looks similar to an unripe peach. Bitter almonds (different from the sweet almonds typically eaten) contain amygdalin, which can release cyanide when metabolized, making them toxic in large quantities."),
        Fact(49, "Chocolate was once used as currency by the Aztecs.", "Food",
            "The Aztecs valued cacao beans so highly that they used them as currency. Historical records from the early colonial period describe price lists: a turkey hen cost 100 beans, a tamale cost 1 bean. Chocolate was consumed as a bitter, frothy drink (xocolatl) mixed with chili, vanilla, and other spices — very different from modern sweet chocolate. Hernán Cortés brought cacao back to Spain in the 1500s, and it spread across Europe, where sugar was added to sweeten it."),
        Fact(50, "Carrots were originally purple before orange varieties were developed.", "Food",
            "Wild carrots are typically white or pale yellow. Purple and yellow cultivated varieties existed in Central Asia for centuries before the 16th century. The familiar orange carrot was selectively developed by Dutch growers in the 17th century, reportedly to honor William of Orange during the Dutch struggle for independence. Orange carrots were selectively bred for their sweeter flavor and higher beta-carotene content. Today, rainbow carrot varieties — including purple, red, white, and yellow — are experiencing a culinary comeback."),
        Fact(51, "Peanuts are legumes, not nuts.", "Food",
            "True nuts (like walnuts, acorns, and chestnuts) are hard-shelled fruits with a seed inside that don't split open at maturity. Peanuts, however, grow underground in pods and are botanically legumes — related to lentils, peas, and beans. The peanut plant flowers above ground, then the stalk bends downward after fertilization, burying the developing pod in the soil, a process called geocarpy. Despite being legumes, peanuts have a nutritional profile (high fat, high protein) similar to tree nuts."),
        Fact(52, "Apples, pears, and roses belong to the same plant family, Rosaceae.", "Food",
            "The Rosaceae family (rose family) is one of the most economically important plant families in the world. It includes roses, apples, pears, plums, cherries, peaches, apricots, raspberries, strawberries, and almonds. Members share characteristic five-petaled flowers and alternate leaves. The family is believed to have originated in Asia and diversified into approximately 3,000 species worldwide. Many Rosaceae fruits are 'pomes' (like apples and pears) — where the flesh develops from the receptacle, not the ovary."),
        Fact(53, "Cashews grow outside the cashew apple fruit, and their shells are toxic.", "Food",
            "The cashew tree (Anacardium occidentale) produces a fleshy, pear-shaped structure called the cashew apple. At the bottom of this apple hangs the true fruit — a kidney-shaped drupe — and inside the drupe is the cashew seed (the nut). The shell surrounding the seed contains urushiol, the same caustic oil found in poison ivy, which causes severe skin reactions. This is why cashews are always sold shelled and roasted — raw cashews in their shells are genuinely dangerous to handle."),
        Fact(54, "Ketchup was sold as medicine in the 1830s.", "Food",
            "In the early 19th century, tomatoes were believed by many Americans to have medicinal properties. Dr. John Cook Bennett promoted tomato-based preparations as cures for liver disease, diarrhea, and indigestion starting around 1834. Tomato ketchup pills were sold as patent medicines. Ironically, at the time, many Americans believed raw tomatoes were poisonous (tomatoes are in the nightshade family). It wasn't until the mid-1800s that tomatoes became widely accepted as safe to eat."),
        Fact(55, "Kopi Luwak is one of the world's most expensive coffees.", "Food",
            "Kopi Luwak (civet coffee) is made from coffee beans that have been eaten and passed through the digestive system of the Asian palm civet. Enzymes in the civet's gut alter the proteins in the beans, reducing bitterness and creating a smoother, more complex flavor profile. It can sell for $100–$600 per kilogram. Unfortunately, commercial demand has led to widespread mistreatment of civets, which are wild animals. Many animal welfare organizations advise against purchasing commercially farmed Kopi Luwak."),

        // Animals
        Fact(56, "A group of flamingos is called a flamboyance.", "Animals",
            "The term 'flamboyance' perfectly suits flamingos — their name itself comes from the Spanish word 'flamenco,' meaning flame-colored. Flamingos are pink due to carotenoid pigments in the algae and crustaceans they eat; without this diet, they would be white. They stand on one leg to conserve body heat, as the other leg is tucked against their warm body. Flamingos are highly social and can form colonies of up to one million birds. Their curved bills are specialized for filter-feeding while upside down."),
        Fact(57, "Sloths can hold their breath longer than dolphins.", "Animals",
            "Sloths can slow their heart rate by over 30% when submerged underwater, allowing them to hold their breath for up to 40 minutes. Dolphins, by comparison, typically hold their breath for 8-10 minutes (though some species can manage up to 15-20 minutes). Sloths are surprisingly good swimmers — they use a slow breaststroke and can travel up to 13.5 meters per minute in water. Their low metabolic rate, which makes them so slow on land, also helps them conserve oxygen when submerged."),
        Fact(58, "Crows can recognize human faces and remember them for years.", "Animals",
            "Research at the University of Washington demonstrated that crows (Corvus brachyrhynchos) can recognize individual human faces and hold grudges against people they perceive as threatening. In experiments where researchers wore masks while capturing and banding crows, the birds later scolded (and recruited other crows to scold) anyone wearing that specific mask — even years later and on different individuals. Crows also show signs of tool use, planning, and social learning, placing them among the most cognitively advanced birds."),
        Fact(59, "A shrimp's heart is located in its head.", "Animals",
            "Shrimp have an open circulatory system where the heart is located in the cephalothorax — the fused head-and-thorax region we colloquially call the 'head.' The heart pumps colorless blood (hemolymph) through open spaces in the body rather than through closed veins and arteries. Shrimp have compound eyes, gills for breathing underwater, and ten legs (making them decapods). The largest shrimp species can reach up to 30 cm in length, while the smallest are microscopic."),
        Fact(60, "Butterflies taste with their feet.", "Animals",
            "Butterflies have chemoreceptors (taste sensors) located on their tarsi — the last segment of their legs. When a butterfly lands on a plant or fruit, these sensors detect chemicals in the surface to determine if it's edible or suitable for laying eggs. Female butterflies use this ability to identify the correct host plants for their larvae. A butterfly's sense of taste is about 200 times more sensitive than the human tongue. They also 'see' UV light patterns on flowers invisible to humans."),
        Fact(61, "Wombats produce cube-shaped droppings.", "Animals",
            "Wombats are the only known animals to produce cube-shaped feces. They use their droppings as territorial markers, stacking them on rocks and logs to communicate with other wombats. The cubic shape prevents the droppings from rolling away, making them more effective markers. Scientists discovered that the cuboid shape forms in the final sections of the wombat's intestines, where varied elasticity in the intestinal walls creates the unusual geometry. This discovery earned the researchers the Ig Nobel Prize in 2019."),
        Fact(62, "Elephants are the only animals that cannot jump.", "Animals",
            "Elephants lack the ankle flexibility and explosive muscle fibers needed to generate the upward thrust required for a jump. Their skeletal structure distributes their enormous weight (up to 6,000 kg for African elephants) through column-like legs with minimal joint flexibility. Despite being unable to jump, elephants are excellent swimmers and can walk up to 80 km per day. They are also the only non-human animals known to mourn their dead and have been observed burying deceased companions."),
        Fact(63, "A group of owls is called a parliament.", "Animals",
            "The collective noun 'parliament' for owls originates from C.S. Lewis's 'The Chronicles of Narnia,' where owls meet to make wise decisions. The term stuck in popular usage. Owls are solitary hunters and rarely gather in large groups outside of roosting. They have asymmetrically placed ears that let them triangulate sound in three dimensions, and their flat facial disk functions like a satellite dish to funnel sound. Some owl species can rotate their heads up to 270° due to special adaptations in their neck vertebrae and blood vessels."),
        Fact(64, "Mantis shrimp can punch with the force of a bullet and have 16 color receptors.", "Animals",
            "The peacock mantis shrimp (Odontodactylus scyllarus) can strike with a velocity of 23 m/s and an acceleration of 10,400 g — generating a force of up to 1,500 Newtons from a limb the size of your thumb. The strike is so fast it creates cavitation bubbles (Rayleigh-Taylor jets) that collapse with additional shockwave force, meaning prey gets hit twice. They also have 16 types of photoreceptors (humans have 3), allowing them to see ultraviolet, visible, and infrared light simultaneously."),
        Fact(65, "Sea otters hold hands while sleeping to avoid drifting apart.", "Animals",
            "Sea otters sleep floating on their backs on the ocean surface. To prevent being separated by currents and waves, otters that live in groups — called rafts — wrap themselves in kelp fronds as anchors, and mating pairs or mothers with pups often hold hands (called 'rafting'). Sea otters have the densest fur of any mammal — about 1 million hairs per square inch — which they constantly groom to maintain its waterproofing and insulating properties since, unlike other marine mammals, they have no blubber."),
        Fact(66, "A group of cats is called a clowder, while a group of kittens is called a kindle.", "Animals",
            "The term 'clowder' dates back to at least the early 19th century and is likely related to the dialectal English word 'clodder,' meaning 'a clotted mass.' 'Kindle' for kittens comes from the Old English word 'kindelen,' meaning to give birth or to produce offspring. Cats (Felis catus) were domesticated from Near Eastern wildcats approximately 10,000 years ago, coinciding with the rise of agriculture. Unlike dogs, cats are self-domesticated — they chose to live near human settlements attracted by rodents in grain stores."),

        // Space
        Fact(67, "There are more stars in the universe than grains of sand on Earth's beaches.", "Space",
            "The observable universe contains an estimated 200 billion trillion stars (2 × 10²³). The number of grains of sand on all of Earth's beaches and deserts is estimated at around 7.5 × 10¹⁸. So there are roughly 10,000 stars for every grain of sand on Earth. Our galaxy, the Milky Way, alone contains 200-400 billion stars. The universe is estimated to be 13.8 billion years old, and its observable edge is about 46 billion light-years away due to the expansion of space."),
        Fact(68, "A day on Venus is longer than its year.", "Space",
            "Venus rotates extremely slowly on its axis — one Venusian day (sidereal rotation period) lasts 243 Earth days. But Venus orbits the Sun in just 224.7 Earth days, making its year shorter than its day. Venus also rotates in retrograde — opposite to most planets — meaning the Sun rises in the west and sets in the east. Its slow rotation means a solar day on Venus (sunrise to sunrise) is actually 117 Earth days. Venus's thick atmosphere creates a crushing pressure 90 times Earth's at the surface."),
        Fact(69, "Footprints on the moon can last for millions of years because there is no wind or rain.", "Space",
            "The Moon has no atmosphere, which means no weather — no wind, no rain, no erosion from moving air or water. The astronaut footprints left during the Apollo missions (1969-1972) are effectively permanent on geological timescales. They may only be erased over millions of years by micrometeorite impacts and solar wind particle bombardment, which slowly erode the lunar surface. The Apollo mission artifacts — landers, equipment, flags — are also still there, though ultraviolet radiation has likely bleached the flags white."),
        Fact(70, "UY Scuti is about 1,700 times the radius of the Sun.", "Space",
            "UY Scuti is one of the largest known stars by radius, estimated at approximately 1,708 times the radius of the Sun (though measurements vary). If placed at the center of our solar system, its surface would extend beyond the orbit of Jupiter. Despite its enormous size, UY Scuti is relatively dim because it is a red supergiant with a cool surface temperature of about 3,365 K. Stars of this type are nearing the end of their lives and will likely explode as supernovae. The Sun, by comparison, is a relatively average-sized star."),
        Fact(71, "About one million Earths could fit inside the Sun.", "Space",
            "The Sun has a radius of about 696,000 km — about 109 times Earth's radius. In terms of volume, approximately 1.3 million Earths could fit inside the Sun. The Sun constitutes about 99.86% of the total mass of the entire solar system. Its core temperature reaches 15 million °C, where nuclear fusion converts hydrogen into helium, releasing the energy that powers all life on Earth. The Sun has been burning for about 4.6 billion years and has roughly another 5 billion years before it expands into a red giant."),
        Fact(72, "The International Space Station travels at about 28,000 km/h.", "Space",
            "The ISS orbits Earth at an altitude of approximately 400 km, traveling at roughly 28,000 km/h (17,500 mph). At this speed, it completes one full orbit every 90 minutes, meaning astronauts aboard see 16 sunrises and 16 sunsets every 24 hours. The ISS has been continuously inhabited since November 2000. It weighs approximately 420,000 kg, spans the area of an American football field, and is the most expensive structure ever built, at an estimated cost of over $150 billion."),
        Fact(73, "Neutron stars can spin up to 700 times per second.", "Space",
            "Rapidly rotating neutron stars are called pulsars because they emit beams of electromagnetic radiation that appear to pulse as the star rotates — like a cosmic lighthouse. The fastest known pulsars are millisecond pulsars, spinning up to 716 times per second (PSR J1748-2446ad). Neutron stars are formed when massive stars collapse in supernovae. They pack about 1.4 times the Sun's mass into a sphere only about 20 km in diameter, making them the densest directly observable objects in the universe."),
        Fact(74, "The Milky Way is estimated to be around 13.6 billion years old.", "Space",
            "The Milky Way galaxy formed shortly after the Big Bang (13.8 billion years ago), making it almost as old as the universe itself. It spans approximately 100,000 light-years in diameter and contains an estimated 200-400 billion stars. At the center is a supermassive black hole called Sagittarius A*, with a mass of approximately 4 million solar masses. The Milky Way is part of the Local Group of galaxies, which includes the Andromeda Galaxy — on a collision course with the Milky Way in about 4.5 billion years."),
        Fact(75, "If all empty atomic space were removed, humanity could fit into a sugar cube.", "Space",
            "Atoms are mostly empty space — the nucleus (protons and neutrons) is about 100,000 times smaller in diameter than the atom itself, meaning the volume ratio is 10¹⁵. If you compressed the human body to remove all this empty space, a 70 kg person would fit into a volume of about 10⁻¹⁶ cubic meters — smaller than a dust particle. Applied to all ~8 billion humans, the combined nuclear material would fit in a volume smaller than a sugar cube. This same principle applies to neutron stars."),
        Fact(76, "Saturn's rings are only about 10 meters thick on average.", "Space",
            "Saturn's rings extend up to 282,000 km from the planet's center — a distance that could nearly span the gap between Earth and the Moon — yet they are only about 10 meters (33 feet) thick on average. The rings are composed mostly of ice particles, rocky debris, and dust ranging in size from micrometers to several meters. Discovered by Galileo in 1610 (though he thought they were 'ears'), the rings are believed to be relatively young — possibly only 10-100 million years old — and may eventually disappear as material spirals into Saturn."),
        Fact(77, "The Sagittarius B2 cloud contains massive amounts of alcohol in space.", "Space",
            "The Sagittarius B2 molecular cloud, located near the center of the Milky Way, contains vast quantities of ethyl alcohol (ethanol) — the same type in alcoholic drinks — among hundreds of other organic molecules. The total ethanol is estimated at enough to fill 10²⁸ liters. Scientists also detected propyl cyanide (the largest organic molecule found in space at the time, 2014) and various amino acid precursors. These discoveries support the theory of panspermia — that organic compounds needed for life can form and travel through space."),

        // Human Body
        Fact(78, "The human body contains enough iron to make a 3-inch nail.", "Human Body",
            "The average adult human body contains about 3-4 grams of iron, mostly in hemoglobin (the protein in red blood cells that carries oxygen). This is roughly the amount needed to forge a small nail about 7-8 cm long. Iron is also found in myoglobin (muscle tissue), enzymes, and stored in the liver and bone marrow. Iron deficiency is the most common nutritional deficiency worldwide, affecting over 2 billion people and leading to iron-deficiency anemia, fatigue, and impaired cognitive function."),
        Fact(79, "A sneeze can travel at about 100 miles per hour.", "Human Body",
            "Sneezes propel droplets and air at speeds estimated between 100-200 mph (160-320 km/h). A 2016 MIT study showed that the droplet cloud from a sneeze can travel up to 8 meters (26 feet) and remain airborne for several minutes. Sneezing is a protective reflex triggered by irritants in the nasal mucosa — it is designed to forcefully expel particles from the upper respiratory tract. The trigeminal nerve coordinates the complex muscular contractions involved, which is why sneezing with your eyes open is nearly impossible."),
        Fact(80, "The brain generates enough electricity to power a small LED bulb.", "Human Body",
            "The human brain has approximately 86 billion neurons, each generating tiny electrical signals called action potentials. At any given time, the aggregate electrical activity generates about 12-25 watts of power — enough to power a low-energy LED light bulb. The brain uses about 20% of the body's total energy despite being only 2% of its weight. This energy is used for maintaining ion gradients across neuron membranes, transmitting signals, and supporting the brain's maintenance functions."),
        Fact(81, "The human nose can detect over 1 trillion different scents.", "Human Body",
            "A 2014 study published in Science estimated that humans can distinguish at least 1 trillion distinct odors — far more than the previously accepted estimate of 10,000. The human olfactory system uses approximately 400 different types of smell receptors in the nasal epithelium, and the brain combines signals from these receptors to identify complex scent mixtures. Smell is the sense most directly connected to memory and emotion, as the olfactory bulb is directly linked to the amygdala and hippocampus."),
        Fact(82, "Bones are about five times stronger than steel of the same density.", "Human Body",
            "Cortical (compact) bone has a tensile strength of about 130 MPa and a density of about 1.85 g/cm³. Grade A structural steel has a tensile strength of around 400 MPa but a density of 7.85 g/cm³ — over four times denser. When compared by strength-to-density ratio (specific strength), bone outperforms steel by roughly five times. Bone is a composite material — the mineral hydroxyapatite provides compressive strength, while collagen fibers provide tensile flexibility, making it both hard and resilient."),
        Fact(83, "Human lungs have a surface area roughly equal to a tennis court.", "Human Body",
            "The lungs contain approximately 480 million tiny air sacs called alveoli. Each alveolus is wrapped in capillaries, and the total surface area available for gas exchange is estimated at 70-100 m² — roughly the size of a singles tennis court (about 260 m² total). This massive surface area allows the lungs to absorb enough oxygen to supply the body's roughly 37 trillion cells. Each day, we breathe approximately 20,000 times and move about 11,000 liters of air through the lungs."),
        Fact(84, "Humans share about 60% of their DNA with bananas.", "Human Body",
            "All living organisms share DNA because they share common ancestry. Humans share about 60% of their genes with bananas, 85% with zebrafish, 90% with cats, and 98.8% with chimpanzees. The shared genes largely encode fundamental cellular functions like DNA replication and metabolism that haven't changed much throughout evolution. The 1.2% difference between humans and chimpanzees, however, includes thousands of gene variants and regulatory differences that account for profound physiological and cognitive distinctions."),
        Fact(85, "The cornea has no blood supply and gets oxygen directly from the air.", "Human Body",
            "The cornea is the only tissue in the human body that is entirely avascular (contains no blood vessels). Blood vessels would scatter light and impair vision, so the cornea receives oxygen directly from the air (dissolved in the tear film on its surface) and nutrients from the aqueous humor behind it. This is why wearing contact lenses for too long can cause problems — they block oxygen from reaching the cornea. It is also why corneal transplants have a high success rate; without blood vessels, the immune system is less likely to reject donor tissue."),
        Fact(86, "Stomach acid is strong enough to dissolve zinc, but the stomach lining constantly replaces itself.", "Human Body",
            "Gastric acid (hydrochloric acid) in the human stomach has a pH of 1.5-3.5 — acidic enough to dissolve metals like zinc and damage many materials. Yet the stomach lining (gastric mucosa) protects itself through a thick layer of alkaline mucus and by completely renewing itself every 3-5 days. The mucus layer maintains a near-neutral pH right at the epithelial surface. When this protection fails — due to H. pylori bacteria, NSAIDs, or excess acid — peptic ulcers develop."),
        Fact(87, "The liver performs over 500 functions in the body.", "Human Body",
            "The liver is the body's largest internal organ and metabolic powerhouse, responsible for over 500 identified functions. These include detoxifying blood from the digestive tract, producing bile for fat digestion, synthesizing plasma proteins (including clotting factors), regulating blood glucose through glycogen storage, metabolizing drugs and alcohol, and producing cholesterol. Remarkably, the liver is the only internal organ capable of natural regeneration — it can regrow to full size even after 75% of it is removed."),
        Fact(88, "Human blood vessels stretch about 100,000 kilometers in total length.", "Human Body",
            "If all the blood vessels in an adult human body (arteries, veins, and capillaries) were laid end to end, they would stretch approximately 100,000 km (60,000 miles) — enough to circle Earth's equator 2.5 times. The majority of this length comes from the microscopic capillaries, which are only 5-10 micrometers in diameter — barely wide enough for a single red blood cell to pass through. The heart pumps blood through this entire network roughly once every minute at rest."),

        // History
        Fact(89, "The Great Wall of China is not visible from space with the naked eye.", "History",
            "Despite the popular claim, the Great Wall of China cannot be seen from space with the naked eye. At about 5-8 meters wide, the wall is too narrow to be resolved by unaided human vision from the altitude of the International Space Station (400 km). This myth has been repeated since the 1900s but was definitively put to rest by Chinese astronaut Yang Liwei, who stated he could not see it from space in 2003. Under ideal conditions, it might be barely visible from low Earth orbit with optical aids."),
        Fact(90, "The shortest war in history lasted between 38 and 45 minutes.", "History",
            "The Anglo-Zanzibar War was fought on August 27, 1896, between the United Kingdom and the Sultanate of Zanzibar. It began at 9:02 AM and ended between 9:40 and 9:45 AM — lasting 38-45 minutes. The war began after Sultan Khalid bin Barghash seized power against British wishes. British naval ships bombarded the palace, the Sultan's small navy was sunk, and the palace flag was shot down, signaling surrender. The war resulted in approximately 500 casualties on the Zanzibari side."),
        Fact(91, "Cleopatra lived closer to the Moon landing than to the construction of the Great Pyramid.", "History",
            "Cleopatra VII ruled Egypt around 51-30 BC, approximately 2,000 years before the Apollo 11 Moon landing in 1969. The Great Pyramid of Giza was completed around 2560 BC — roughly 2,500 years before Cleopatra's time. So the Moon landing (1969 AD) is about 2,000 years from Cleopatra, while the Great Pyramid (2560 BC) is about 2,500 years from her — making Cleopatra temporally closer to us than to the pyramid builders. This illustrates just how ancient the Egyptian Old Kingdom civilization truly was."),
        Fact(92, "Vikings used stars and sunstones to navigate on cloudy days.", "History",
            "Viking navigators used a crystal called a 'sólarsteinn' (sunstone) — most likely Iceland spar (optical calcite) — to locate the sun's position on overcast days. When held up and rotated, Iceland spar polarizes light, showing a pattern that indicates the direction of the sun even through clouds or fog. A 2013 study confirmed that this technique can locate the sun's position to within a few degrees of accuracy. Combined with star navigation, ocean currents, wave patterns, and bird behavior, Viking navigators were remarkably sophisticated."),
        Fact(93, "Napoleon Bonaparte was around 5'7, average for his time.", "History",
            "Napoleon's reputation for being very short is largely a myth arising from a confusion between French and English measurement systems. His height was recorded as 5 pieds 2 pouces in French units — approximately 168 cm (5 feet 6-7 inches) in modern metric, which was average or slightly above average for a French man of his era. The confusion arose because British propaganda converted the measurement incorrectly, and his nickname 'le petit caporal' ('the little corporal') referred to his common touch with soldiers, not his stature."),
        Fact(94, "The Roman Empire lasted for more than 1,000 years.", "History",
            "If you count the Western Roman Empire alone, it lasted from 27 BC (when Augustus became emperor) to 476 AD — about 500 years. However, the Eastern Roman Empire (Byzantine Empire), which continued with Roman traditions and considered itself the true continuation of Rome, lasted from 330 AD (founding of Constantinople) until 1453 AD when it fell to the Ottoman Turks. This means Roman civilization, broadly defined, endured for approximately 1,500 years — one of the longest-lasting political entities in history."),
        Fact(95, "Oxford University is older than the Aztec Empire.", "History",
            "Teaching at Oxford began around 1096-1167 AD, and the University of Oxford was formally recognized in the 12th century. The Aztec Empire, by contrast, was founded around 1428 AD with the Triple Alliance. Oxford received its royal charter in 1248 — almost 200 years before the Aztecs established their empire. Oxford is the oldest English-speaking university in the world and has been in continuous operation for over 900 years, making it one of the oldest universities still functioning on Earth."),
        Fact(96, "Ancient Egyptians used moldy bread as an early antibiotic.", "History",
            "Ancient Egyptian medical texts, including the Ebers Papyrus (circa 1550 BC), describe applying moldy bread to infected wounds. Priests and healers observed that certain molds inhibited infection — unknowingly harnessing the antibiotic properties of Penicillium mold, the same genus from which Alexander Fleming isolated penicillin in 1928. Similar practices were documented in ancient Serbia, China, and Greece. This represents an empirical discovery of antibiotics nearly 3,500 years before modern medicine formally understood the mechanism."),
        Fact(97, "The Great Fire of London destroyed over 13,000 houses but reportedly killed fewer than 10 people.", "History",
            "The Great Fire of London burned from September 2-5, 1666, destroying 13,200 houses, 87 churches (including St. Paul's Cathedral), and most of the buildings of the City of London. Remarkably, official death toll records show fewer than 10 confirmed fatalities — though historians believe the true number may be much higher, as deaths of the poor were not systematically recorded. The fire led to major urban reforms: buildings were required to be made of brick or stone instead of wood, and London's first organized fire insurance system was established."),
        Fact(98, "Albert Einstein was offered the presidency of Israel in 1952 but declined.", "History",
            "When Israel's first president Chaim Weizmann died in November 1952, Prime Minister David Ben-Gurion offered the presidency to Albert Einstein. Einstein, then 73 and living in Princeton, New Jersey, declined the offer graciously but firmly, stating he lacked the natural aptitude and experience for dealing with people and official functions. Einstein had been a committed Zionist and helped raise funds for Hebrew University in Jerusalem, which he helped found in 1925. He died in 1955, leaving his scientific papers to Hebrew University."),
        Fact(99, "ENIAC weighed 27 tons and filled an entire room.", "History",
            "ENIAC (Electronic Numerical Integrator and Computer), completed in 1945 at the University of Pennsylvania, was the first general-purpose electronic digital computer. It weighed approximately 27 metric tons, occupied 1,800 square feet (167 m²), contained 17,468 vacuum tubes, 7,200 crystal diodes, and consumed 150 kilowatts of power — enough to dim the lights of an entire Philadelphia neighborhood when turned on. It could perform about 5,000 additions per second. Modern smartphones perform billions of operations per second in a device weighing 200 grams."),
        Fact(100, "Shaking hands originated as a way to show neither person carried a weapon.", "History",
            "The handshake is believed to have originated in ancient Greece as a gesture of peace, demonstrating that the right hand (the weapon-wielding hand for most people) held no sword or dagger. Carvings depicting handshakes between rulers have been found dating back to the 9th century BC in Assyria. Medieval European knights would grasp each other's sword hand to feel for concealed weapons and sometimes pump the arms up and down to dislodge any hidden blades in the sleeve. Today, handshakes serve as greetings, deal-sealing gestures, and symbols of sportsmanship.")
    )

    private val favorites = mutableListOf<Fact>()
    var selectedTopics = mutableSetOf<String>()

    fun getRandomFact(): Fact {
        val pool = if (selectedTopics.isEmpty()) facts
        else facts.filter { it.topic in selectedTopics }
        return (if (pool.isEmpty()) facts else pool).random()
    }

    fun isFavorite(fact: Fact): Boolean = favorites.contains(fact)

    fun saveFavorite(fact: Fact) {
        if (!favorites.contains(fact)) favorites.add(fact)
    }

    fun removeFavorite(position: Int) {
        if (position in favorites.indices) favorites.removeAt(position)
    }

    fun removeFavoriteByFact(fact: Fact) {
        favorites.remove(fact)
    }

    fun getFavorites(): List<Fact> = favorites.toList()
}